async function main() {
  const now = new Date();

  const existing = await db
    .select({ id: submissions.id, publicId: submissions.publicId })
    .from(submissions)
    .where(eq(sql`${submissions.payload}->>'headline'`, HEADLINE))
    .limit(1);

  if (existing.length) {
    const row = existing[0];
    await db
      .update(submissions)
      .set({
        payload,
        status: "approved",
        featured: true,
        publishedAt: now,
        updatedAt: now,
        submitterHandle: "RexIntel",
      })
      .where(eq(submissions.id, row.id));
    console.log(`Updated existing exposé row (id=${row.id}, publicId=${row.publicId})`);
    console.log(`  /intel/${row.publicId}`);
  } else {
    const [inserted] = await db
      .insert(submissions)
      .values({
        type: "intel",
        status: "approved",
        payload,
        submitterHandle: "RexIntel",
        publishedAt: now,
        featured: true,
      })
      .returning({ id: submissions.id, publicId: submissions.publicId });
    console.log(`Inserted exposé (id=${inserted.id}, publicId=${inserted.publicId})`);
    console.log(`  /intel/${inserted.publicId}`);
  }

  console.log(`\nFeatured at the top of /intel signals lane.`);
  console.log(`Body length: ${body.length} chars`);
}

main()
  .then(() => process.exit(0))
  .catch((e) => {
    console.error(e);
    process.exit(1);
  });
